A router machine models each route as a state and exposes a single `NAVIGATE` event whose `to` payload picks the target via guarded transitions. Declaring guards in `setup.guards` keeps them reusable across routes.

```typescript
import { setup, assign } from 'xstate';

type Route = 'home' | 'profile' | 'settings';
type Ctx = { path: Route; authed: boolean };
type Ev =
  | { type: 'NAVIGATE'; to: Route }
  | { type: 'LOGIN' }
  | { type: 'LOGOUT' };

export const routerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    canEnterSettings: ({ context, event }) =>
      event.type === 'NAVIGATE' && (event.to !== 'settings' || context.authed),
  },
  actions: {
    setPath: assign({
      path: ({ event }) => (event.type === 'NAVIGATE' ? event.to : 'home'),
    }),
  },
}).createMachine({
  id: 'router',
  context: { path: 'home', authed: false },
  initial: 'home',
  on: {
    LOGIN: { actions: assign({ authed: () => true }) },
    LOGOUT: { actions: assign({ authed: () => false }) },
  },
  states: {
    home: {
      on: {
        NAVIGATE: [
          { guard: 'canEnterSettings', target: 'settings', actions: 'setPath' },
          { target: 'profile', actions: 'setPath' },
        ],
      },
    },
    profile: {
      on: {
        NAVIGATE: [
          { guard: 'canEnterSettings', target: 'settings', actions: 'setPath' },
          { target: 'home', actions: 'setPath' },
        ],
      },
    },
    settings: {
      on: { NAVIGATE: { target: 'home', actions: 'setPath' } },
    },
  },
});
```

Invoke the child machine with `onDone` on the state that hosts it. When the child reaches a `final` state with `output`, the parent's `onDone` fires and you transition away — no manual `sendParent` needed.

```typescript
import { setup, assign } from 'xstate';

const wizard = setup({
  types: {
    events: {} as { type: 'DONE' },
    output: {} as { ok: boolean },
  },
}).createMachine({
  id: 'wizard',
  initial: 'step',
  states: {
    step: { on: { DONE: 'finished' } },
    finished: { type: 'final', output: () => ({ ok: true }) },
  },
});

type Ctx = { lastResult: boolean | null };
type Ev = { type: 'GO_WIZARD' } | { type: 'DONE' };

export const routerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { wizard },
}).createMachine({
  id: 'router',
  context: { lastResult: null },
  initial: 'home',
  states: {
    home: { on: { GO_WIZARD: 'wizardRoute' } },
    wizardRoute: {
      invoke: {
        src: 'wizard',
        onDone: {
          target: 'home',
          actions: assign({ lastResult: ({ event }) => event.output.ok }),
        },
      },
    },
  },
});
```

Hierarchical routes map cleanly onto compound states: `settings` is a parent, `profile` and `billing` are children. The parent's `initial` acts as the default subroute, and relative targets keep navigation scoped. Typed events with a discriminated `to` payload make transitions exhaustive.

```typescript
import { setup, assign } from 'xstate';

type Path = 'home' | 'settings.profile' | 'settings.billing';
type Ctx = { path: Path };
type Ev = { type: 'NAVIGATE'; to: Path };

export const routerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    setPath: assign({
      path: ({ event }) => event.to,
    }),
  },
}).createMachine({
  id: 'router',
  context: { path: 'home' },
  initial: 'home',
  states: {
    home: {
      on: {
        NAVIGATE: [
          { guard: ({ event }) => event.to === 'settings.profile', target: 'settings.profile', actions: 'setPath' },
          { guard: ({ event }) => event.to === 'settings.billing', target: 'settings.billing', actions: 'setPath' },
        ],
      },
    },
    settings: {
      initial: 'profile',
      on: { NAVIGATE: { guard: ({ event }) => event.to === 'home', target: 'home', actions: 'setPath' } },
      states: {
        profile: {},
        billing: {},
      },
    },
  },
});
```

```typescript
import { setup, assign } from 'xstate';

type Route = 'public' | 'dashboard' | 'admin' | 'billing';
type Ctx = { route: Route; role: 'guest' | 'user' | 'admin'; paid: boolean };
type Ev = { type: 'GOTO'; to: Route } | { type: 'SET_ROLE'; role: Ctx['role'] } | { type: 'SET_PAID'; paid: boolean };

export const routerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    isPublic: ({ event }) => event.type === 'GOTO' && event.to === 'public',
    needsUser: ({ context, event }) =>
      event.type === 'GOTO' && event.to === 'dashboard' && context.role !== 'guest',
    needsAdmin: ({ context, event }) =>
      event.type === 'GOTO' && event.to === 'admin' && context.role === 'admin',
    needsPaid: ({ context, event }) =>
      event.type === 'GOTO' && event.to === 'billing' && context.paid,
  },
  actions: {
    commit: assign({ route: ({ event }) => (event.type === 'GOTO' ? event.to : 'public') }),
    setRole: assign({ role: ({ event }) => (event.type === 'SET_ROLE' ? event.role : 'guest') }),
    setPaid: assign({ paid: ({ event }) => (event.type === 'SET_PAID' ? event.paid : false) }),
  },
}).createMachine({
  id: 'router',
  context: { route: 'public', role: 'guest', paid: false },
  initial: 'public',
  on: {
    SET_ROLE: { actions: 'setRole' },
    SET_PAID: { actions: 'setPaid' },
    GOTO: [
      { guard: 'isPublic', target: '.public', actions: 'commit' },
      { guard: 'needsUser', target: '.dashboard', actions: 'commit' },
      { guard: 'needsAdmin', target: '.admin', actions: 'commit' },
      { guard: 'needsPaid', target: '.billing', actions: 'commit' },
    ],
  },
  states: {
    public: {},
    dashboard: {},
    admin: {},
    billing: {},
  },
});
```

Add a `notFound` fallback route and a `ROUTE_ERROR` event that transitions there to this v5 router machine:

```typescript
import { setup, assign } from 'xstate';

type Route = 'home' | 'about';
type Ctx = { route: Route };
type Ev = { type: 'GOTO'; to: Route };

export const routerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: { commit: assign({ route: ({ event }) => event.to }) },
}).createMachine({
  id: 'router',
  context: { route: 'home' },
  initial: 'home',
  states: {
    home: { on: { GOTO: { target: 'about', actions: 'commit' } } },
    about: { on: { GOTO: { target: 'home', actions: 'commit' } } },
  },
});
```

Extend the event union with `ROUTE_ERROR`, widen `Route` to include `'notFound'`, and add a root-level `on` handler so any state transitions to the fallback.

```typescript
import { setup, assign } from 'xstate';

type Route = 'home' | 'about' | 'notFound';
type Ctx = { route: Route; reason: string | null };
type Ev = { type: 'GOTO'; to: Exclude<Route, 'notFound'> } | { type: 'ROUTE_ERROR'; reason: string };

export const routerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    commit: assign({ route: ({ event }) => (event.type === 'GOTO' ? event.to : 'notFound') }),
    setReason: assign({ reason: ({ event }) => (event.type === 'ROUTE_ERROR' ? event.reason : null) }),
  },
}).createMachine({
  id: 'router',
  context: { route: 'home', reason: null },
  initial: 'home',
  on: {
    ROUTE_ERROR: { target: '.notFound', actions: ['setReason', 'commit'] },
  },
  states: {
    home: { on: { GOTO: { target: 'about', actions: 'commit' } } },
    about: { on: { GOTO: { target: 'home', actions: 'commit' } } },
    notFound: { on: { GOTO: [{ target: 'home', actions: 'commit' }] } },
  },
});
```

```typescript
import { setup, assign } from 'xstate';

const loginMachine = setup({
  types: {
    events: {} as { type: 'SUBMIT'; userId: string },
    output: {} as { userId: string },
    context: {} as { userId: string | null },
  },
}).createMachine({
  id: 'login',
  context: { userId: null },
  initial: 'form',
  states: {
    form: {
      on: {
        SUBMIT: {
          target: 'done',
          actions: assign({ userId: ({ event }) => event.userId }),
        },
      },
    },
    done: {
      type: 'final',
      output: ({ context }) => ({ userId: context.userId ?? '' }),
    },
  },
});

type Route = 'home' | 'login';
type Ctx = { route: Route; userId: string | null };
type Ev = { type: 'GOTO'; to: Route };

export const routerMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { loginMachine },
}).createMachine({
  id: 'router',
  context: { route: 'home', userId: null },
  initial: 'home',
  states: {
    home: { on: { GOTO: { target: 'login' } } },
    login: {
      invoke: {
        src: 'loginMachine',
        onDone: {
          target: 'home',
          actions: assign({ userId: ({ event }) => event.output.userId }),
        },
      },
    },
  },
