```

A single `active` state is sufficient; each event is an `assign`. Keeping page bounded with `Math.max` avoids going negative.

```typescript
import { setup, assign } from 'xstate';

type Col = 'name' | 'price' | 'stock';
type Ctx = { sortBy: Col | null; filter: string; page: number };
type Ev =
  | { type: 'SORT'; column: Col }
  | { type: 'FILTER'; text: string }
  | { type: 'NEXT_PAGE' }
  | { type: 'PREV_PAGE' };

export const tableMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
}).createMachine({
  id: 'table',
  context: { sortBy: null, filter: '', page: 0 },
  initial: 'active',
  states: {
    active: {
      on: {
        SORT: {
          actions: assign({
            sortBy: ({ event }) => event.column,
            page: () => 0,
          }),
        },
        FILTER: {
          actions: assign({
            filter: ({ event }) => event.text,
            page: () => 0,
          }),
        },
        NEXT_PAGE: {
          actions: assign({ page: ({ context }) => context.page + 1 }),
        },
        PREV_PAGE: {
          actions: assign({ page: ({ context }) => Math.max(0, context.page - 1) }),
        },
      },
    },
  },
});
```

Hold the pending text in context, enter a `debouncing` state on FILTER, and `after: 300` commits the text. Re-entering `debouncing` on each keystroke resets the timer.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { text: string; pending: string };
type Ev = { type: 'FILTER'; text: string };

export const filterMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
}).createMachine({
  id: 'filter',
  context: { text: '', pending: '' },
  initial: 'idle',
  states: {
    idle: {
      on: {
        FILTER: {
          target: 'debouncing',
          actions: assign({ pending: ({ event }) => event.text }),
        },
      },
    },
    debouncing: {
      on: {
        FILTER: {
          target: 'debouncing',
          reenter: true,
          actions: assign({ pending: ({ event }) => event.text }),
        },
      },
      after: {
        300: {
          target: 'idle',
          actions: assign({ text: ({ context }) => context.pending }),
        },
      },
    },
  },
});
```

Store the current column and direction in context. On `SORT`, branch by whether it's the same column: clicking the active column advances `asc → desc → none`, clicking a different column resets to `asc`. Keeping the transition logic in a single `assign` keeps the state chart flat.

```typescript
import { setup, assign } from 'xstate';

type Col = 'name' | 'price';
type Dir = 'asc' | 'desc' | null;
type Ctx = { col: Col | null; dir: Dir };
type Ev = { type: 'SORT'; column: Col };

export const sortMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
}).createMachine({
  id: 'sort',
  context: { col: null, dir: null },
  initial: 'idle',
  states: {
    idle: {
      on: {
        SORT: {
          actions: assign(({ context, event }) => {
            if (context.col !== event.column) {
              return { col: event.column, dir: 'asc' as Dir };
            }
            const next: Dir = context.dir === 'asc' ? 'desc' : context.dir === 'desc' ? null : 'asc';
            return { col: next === null ? null : event.column, dir: next };
          }),
        },
      },
    },
  },
});
```

```typescript
import { setup, assign, enqueueActions } from 'xstate';

type Col = 'id' | 'title' | 'created';
type Ctx = { sortBy: Col | null; filter: string; page: number; totalRows: number };
type Ev =
  | { type: 'SORT'; column: Col }
  | { type: 'FILTER'; text: string }
  | { type: 'GOTO_PAGE'; page: number }
  | { type: 'SET_TOTAL'; total: number };

const PAGE_SIZE = 20;

export const tableMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    applyFilter: assign({
      filter: ({ event }) => (event.type === 'FILTER' ? event.text : ''),
      page: () => 0,
    }),
    applyTotal: assign({
      totalRows: ({ event }) => (event.type === 'SET_TOTAL' ? event.total : 0),
    }),
    gotoPage: assign({
      page: ({ context, event }) => {
        if (event.type !== 'GOTO_PAGE') return context.page;
        const maxPage = Math.max(0, Math.ceil(context.totalRows / PAGE_SIZE) - 1);
        return Math.min(Math.max(0, event.page), maxPage);
      },
    }),
    applySort: enqueueActions(({ enqueue, event }) => {
      if (event.type !== 'SORT') return;
      enqueue.assign({ sortBy: event.column, page: () => 0 });
    }),
  },
}).createMachine({
  id: 'table',
  context: { sortBy: null, filter: '', page: 0, totalRows: 0 },
  initial: 'ready',
  states: {
    ready: {
      on: {
        SORT: { actions: 'applySort' },
        FILTER: { actions: 'applyFilter' },
        GOTO_PAGE: { actions: 'gotoPage' },
        SET_TOTAL: { actions: 'applyTotal' },
      },
    },
  },
});
```

Refactor this v5 machine to use `setup({ actions, guards })` with string references instead of inline callbacks:

```typescript
import { setup, assign } from 'xstate';
type Ctx = { page: number; total: number };
type Ev = { type: 'NEXT' } | { type: 'PREV' };
export const m = setup({
  types: { context: {} as Ctx, events: {} as Ev },
}).createMachine({
  id: 'p',
  context: { page: 0, total: 3 },
  initial: 'idle',
  states: {
    idle: {
      on: {
        NEXT: {
          guard: ({ context }) => context.page < context.total - 1,
          actions: assign({ page: ({ context }) => context.page + 1 }),
        },
        PREV: {
          guard: ({ context }) => context.page > 0,
          actions: assign({ page: ({ context }) => context.page - 1 }),
        },
      },
    },
  },
});
```

Extract the guards and actions into `setup` so the state body only references them by name.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { page: number; total: number };
type Ev = { type: 'NEXT' } | { type: 'PREV' };

export const m = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    hasNext: ({ context }) => context.page < context.total - 1,
    hasPrev: ({ context }) => context.page > 0,
  },
  actions: {
    next: assign({ page: ({ context }) => context.page + 1 }),
    prev: assign({ page: ({ context }) => context.page - 1 }),
  },
}).createMachine({
  id: 'p',
  context: { page: 0, total: 3 },
  initial: 'idle',
  states: {
    idle: {
      on: {
        NEXT: { guard: 'hasNext', actions: 'next' },
        PREV: { guard: 'hasPrev', actions: 'prev' },
      },
    },
  },
});
```

