Widen the event union with `RESET` and add a handler at the root-level `on` so it applies from any state.

```typescript
import { setup, assign } from 'xstate';

type Ctx = { sortBy: string | null; filter: string; page: number };
type Ev =
  | { type: 'SORT'; column: string }
  | { type: 'FILTER'; text: string }
  | { type: 'RESET' };

export const tableMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actions: {
    reset: assign({ sortBy: () => null, filter: () => '', page: () => 0 }),
  },
}).createMachine({
  id: 'table',
  context: { sortBy: null, filter: '', page: 0 },
  initial: 'active',
  on: { RESET: { actions: 'reset' } },
  states: {
    active: {
      on: {
        SORT: { actions: assign({ sortBy: ({ event }) => event.column }) },
        FILTER: { actions: assign({ filter: ({ event }) => event.text }) },
      },
    },
  },
