Model the cart as a single `shopping` state until checkout, with a `checkingOut` state that transitions to a `final` confirm state. Use a guard to block checkout on empty carts.

```typescript
import { setup, assign } from 'xstate';

type Item = { id: string; price: number };
type Ctx = { items: Item[]; promo: string | null };
type Ev =
  | { type: 'ADD_ITEM'; item: Item }
  | { type: 'REMOVE_ITEM'; id: string }
  | { type: 'APPLY_PROMO'; code: string }
  | { type: 'CHECKOUT' };

export const cartMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    notEmpty: ({ context }) => context.items.length > 0,
  },
}).createMachine({
  id: 'cart',
  context: { items: [], promo: null },
  initial: 'shopping',
  states: {
    shopping: {
      on: {
        ADD_ITEM: {
          actions: assign({
            items: ({ context, event }) => [...context.items, event.item],
          }),
        },
        REMOVE_ITEM: {
          actions: assign({
            items: ({ context, event }) => context.items.filter((it) => it.id !== event.id),
          }),
        },
        APPLY_PROMO: {
          actions: assign({ promo: ({ event }) => event.code }),
        },
        CHECKOUT: { guard: 'notEmpty', target: 'checkingOut' },
      },
    },
    checkingOut: {
      on: { CHECKOUT: 'confirmed' },
    },
    confirmed: { type: 'final' },
  },
});
```

Move to a `validatingPromo` state and `invoke` a `fromPromise` actor. `onDone` writes the discount; `onError` bounces back without mutating the cart.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { code: string | null; discount: number };
type Ev = { type: 'APPLY_PROMO'; code: string };

const validate = fromPromise<number, { code: string }>(async ({ input }) => {
  const res = await fetch(`/promo/${input.code}`);
  if (!res.ok) throw new Error('invalid');
  const data = (await res.json()) as { discount: number };
  return data.discount;
});

export const promoMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { validate },
}).createMachine({
  id: 'promo',
  context: { code: null, discount: 0 },
  initial: 'idle',
  states: {
    idle: {
      on: {
        APPLY_PROMO: {
          target: 'validatingPromo',
          actions: assign({ code: ({ event }) => event.code }),
        },
      },
    },
    validatingPromo: {
      invoke: {
        src: 'validate',
        input: ({ context }) => ({ code: context.code ?? '' }),
        onDone: {
          target: 'idle',
          actions: assign({ discount: ({ event }) => event.output }),
        },
        onError: {
          target: 'idle',
          actions: assign({ code: () => null, discount: () => 0 }),
        },
      },
    },
  },
});
```

The cleanest shape is a `Map<id, { item, qty }>` modelled as a plain object keyed by id. On ADD_ITEM you check whether the key exists and either bump `qty` or insert a new entry, all inside a single `assign`. REMOVE_ITEM decrements and prunes zero-quantity rows.

```typescript
import { setup, assign } from 'xstate';

type Item = { id: string; price: number };
type Line = { item: Item; qty: number };
type Ctx = { lines: Record<string, Line> };
type Ev = { type: 'ADD'; item: Item } | { type: 'REMOVE'; id: string };

export const cartMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
}).createMachine({
  id: 'cart',
  context: { lines: {} },
  initial: 'open',
  states: {
    open: {
      on: {
        ADD: {
          actions: assign({
            lines: ({ context, event }) => {
              const prev = context.lines[event.item.id];
              const next = prev ? { ...prev, qty: prev.qty + 1 } : { item: event.item, qty: 1 };
              return { ...context.lines, [event.item.id]: next };
            },
          }),
        },
        REMOVE: {
          actions: assign({
            lines: ({ context, event }) => {
              const prev = context.lines[event.id];
              if (!prev) return context.lines;
              if (prev.qty <= 1) {
                const { [event.id]: _drop, ...rest } = context.lines;
                return rest;
              }
              return { ...context.lines, [event.id]: { ...prev, qty: prev.qty - 1 } };
            },
          }),
        },
      },
    },
  },
});
```

```typescript
import { setup, assign } from 'xstate';

type Item = { id: string; price: number };
type Ctx = { items: Item[]; tax: number };
type Ev =
  | { type: 'ADD'; item: Item }
  | { type: 'CHECKOUT' }
  | { type: 'SHIPPED' }
  | { type: 'PAID' }
  | { type: 'TAX_UPDATED'; amount: number };

export const cartMachine = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  guards: {
    underCap: ({ context }) => context.items.reduce((s, it) => s + it.price, 0) <= 500,
    nonEmpty: ({ context }) => context.items.length > 0,
  },
  actions: {
    addItem: assign({ items: ({ context, event }) => (event.type === 'ADD' ? [...context.items, event.item] : context.items) }),
    setTax: assign({ tax: ({ event }) => (event.type === 'TAX_UPDATED' ? event.amount : 0) }),
  },
}).createMachine({
  id: 'cart',
  context: { items: [], tax: 0 },
  type: 'parallel',
  states: {
    flow: {
      initial: 'cart',
      states: {
        cart: {
          on: {
            ADD: { actions: 'addItem' },
            CHECKOUT: { guard: 'nonEmpty', target: 'shipping' },
          },
        },
        shipping: { on: { SHIPPED: { guard: 'underCap', target: 'payment' } } },
        payment: { on: { PAID: 'confirmed' } },
        confirmed: { type: 'final' },
      },
    },
    tax: {
      initial: 'watching',
      states: {
        watching: {
          on: { TAX_UPDATED: { actions: 'setTax' } },
        },
      },
    },
  },
});
```

```typescript
import { setup, assign } from 'xstate';

type Item = { id: string; price: number };
type PromoState =
  | { kind: 'none' }
  | { kind: 'pending'; code: string }
  | { kind: 'applied'; code: string; discount: number }
  | { kind: 'rejected'; code: string; reason: string };

type Ctx = { items: Item[]; promo: PromoState };
type Ev =
  | { type: 'ADD'; item: Item }
  | { type: 'SUBMIT_PROMO'; code: string }
  | { type: 'PROMO_OK'; code: string; discount: number }
  | { type: 'PROMO_FAIL'; code: string; reason: string }
