`fromCallback` is ideal for wrapping DOM listeners: it owns the `addEventListener` / cleanup pair and speaks to the parent via `sendBack`.

```typescript
import { setup, assign, fromCallback } from 'xstate';

type Ev =
  | { type: 'ARROW_DOWN' }
  | { type: 'ARROW_UP' }
  | { type: 'ESCAPE' };

type Ctx = { highlighted: number };

const keys = fromCallback<Ev>(({ sendBack }) => {
  const onKey = (e: KeyboardEvent) => {
    if (e.key === 'ArrowDown') sendBack({ type: 'ARROW_DOWN' });
    else if (e.key === 'ArrowUp') sendBack({ type: 'ARROW_UP' });
    else if (e.key === 'Escape') sendBack({ type: 'ESCAPE' });
  };
  if (typeof window !== 'undefined') {
    window.addEventListener('keydown', onKey);
  }
  return () => {
    if (typeof window !== 'undefined') {
      window.removeEventListener('keydown', onKey);
    }
  };
});

export const autocomplete = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { keys },
}).createMachine({
  id: 'autocomplete',
  context: { highlighted: 0 },
  initial: 'open',
  invoke: { src: 'keys' },
  states: {
    open: {
      on: {
        ARROW_DOWN: { actions: assign({ highlighted: ({ context }) => context.highlighted + 1 }) },
        ARROW_UP: { actions: assign({ highlighted: ({ context }) => Math.max(0, context.highlighted - 1) }) },
        ESCAPE: 'closed',
      },
    },
    closed: {},
