      ),
      on: {
        LEAVE: { target: 'away', actions: cancel('scheduled') },
        REFETCH: 'refetching',
      },
    },
    refetching: {
      invoke: {
        src: 'load',
        onDone: {
          target: 'showing',
          actions: assign({ data: ({ event }) => event.output }),
        },
        onError: { target: 'showing' },
      },
    },
  },
});
```

