Widen `Ctx` with `error`, branch the failure path through a dedicated `failed` state, and allow a RETRY event from it.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { data: string | null; error: string | null };
type Ev = { type: 'FETCH' } | { type: 'RETRY' };

const load = fromPromise<string, void>(async () => 'ok');

export const loader = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { load },
}).createMachine({
  id: 'loader',
  context: { data: null, error: null },
