  states: {
    idle: { on: { FETCH: 'loading' } },
    loading: {
      invoke: {
        src: 'load',
        onDone: {
          target: 'idle',
          actions: assign({ data: ({ event }) => event.output, error: () => null }),
        },
        onError: {
          target: 'failed',
          actions: assign({
            error: ({ event }) => (event.error instanceof Error ? event.error.message : 'unknown'),
          }),
        },
      },
    },
    failed: {
      on: { RETRY: 'loading' },
    },
  },
});
