Typed `CALLBACK` event carries the authorization code; a `fromPromise` actor does the token exchange.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { code: string | null; token: string | null; error: string | null };
type Ev =
  | { type: 'LOGIN' }
  | { type: 'CALLBACK'; code: string }
  | { type: 'LOGOUT' };

const exchange = fromPromise<string, { code: string }>(async ({ input }) => `tok-${input.code}`);

export const oauth = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { exchange },
}).createMachine({
  id: 'oauth',
  context: { code: null, token: null, error: null },
  initial: 'idle',
  states: {
    idle: { on: { LOGIN: 'redirecting' } },
    redirecting: { on: { CALLBACK: { target: 'exchanging', actions: assign({ code: ({ event }) => event.code }) } } },
    exchanging: {
      invoke: {
        src: 'exchange',
        input: ({ context }) => ({ code: context.code ?? '' }),
        onDone: {
          target: 'authenticated',
          actions: assign({ token: ({ event }) => event.output, error: () => null }),
        },
        onError: {
          target: 'failed',
          actions: assign({
            error: ({ event }) => (event.error instanceof Error ? event.error.message : 'unknown'),
          }),
        },
      },
    },
    authenticated: { on: { LOGOUT: 'idle' } },
    failed: { on: { LOGIN: 'redirecting' } },
  },
});
```

Use two invoked actors: `callApi` first; `onError` transitions to `refreshing`; after refresh, re-enter `callingApi` via `reenter: true`.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { token: string | null; payload: string | null };
type Ev = { type: 'CALL' };

const callApi = fromPromise<string, { token: string | null }>(async ({ input }) => {
  if (!input.token) throw new Error('401');
  return 'data';
});
const refresh = fromPromise<string, void>(async () => 'new-token');

export const api = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { callApi, refresh },
}).createMachine({
  id: 'api',
  context: { token: null, payload: null },
  initial: 'idle',
  states: {
    idle: { on: { CALL: 'callingApi' } },
    callingApi: {
      invoke: {
        src: 'callApi',
        input: ({ context }) => ({ token: context.token }),
        onDone: {
          target: 'idle',
          actions: assign({ payload: ({ event }) => event.output }),
        },
        onError: { target: 'refreshing' },
      },
    },
    refreshing: {
      invoke: {
        src: 'refresh',
        onDone: {
          target: 'callingApi',
          reenter: true,
          actions: assign({ token: ({ event }) => event.output }),
        },
        onError: { target: 'idle' },
      },
    },
  },
});
```

In PKCE the client generates a `verifier` before redirecting and later presents it during token exchange. Modeled as an FSM, that means `idle` creates and stores the verifier on LOGIN, `awaitingCallback` captures the `code`, and `exchanging` invokes the token endpoint with both `code` and `verifier` as typed input. The verifier is cleared on success to avoid leaking it post-auth.

```typescript
import { setup, assign, fromPromise } from 'xstate';

type Ctx = { verifier: string | null; code: string | null; token: string | null };
type Ev = { type: 'LOGIN' } | { type: 'CALLBACK'; code: string };

const exchange = fromPromise<string, { code: string; verifier: string }>(
  async ({ input }) => `tok-${input.code}-${input.verifier}`,
);

export const oauthPkce = setup({
  types: { context: {} as Ctx, events: {} as Ev },
  actors: { exchange },
}).createMachine({
  id: 'oauthPkce',
  context: { verifier: null, code: null, token: null },
  initial: 'idle',
  states: {
    idle: {
      on: {
        LOGIN: {
          target: 'awaitingCallback',
          actions: assign({ verifier: () => Math.random().toString(36).slice(2) }),
        },
      },
    },
    awaitingCallback: {
      on: {
        CALLBACK: {
          target: 'exchanging',
          actions: assign({ code: ({ event }) => event.code }),
        },
      },
    },
    exchanging: {
      invoke: {
        src: 'exchange',
        input: ({ context }) => ({ code: context.code ?? '', verifier: context.verifier ?? '' }),
        onDone: {
          target: 'authenticated',
          actions: assign({
            token: ({ event }) => event.output,
            verifier: () => null,
          }),
        },
        onError: { target: 'idle' },
      },
    },
    authenticated: {},
  },
});
```

