import { setup, assign } from 'xstate';

type Session =
  | { kind: 'anonymous' }
  | { kind: 'active'; token: string; expiresAt: number }
  | { kind: 'expired'; lastToken: string };

type Ctx = { session: Session };
type Ev =
  | { type: 'LOGIN'; token: string; ttlMs: number }
  | { type: 'EXPIRE' }
  | { type: 'REVOKE' };

export const sessionMachine = setup({
  types: {
    context: {} as Ctx,
    events: {} as Ev,
    output: {} as { finalSession: Session },
  },
}).createMachine({
  id: 'session',
  context: { session: { kind: 'anonymous' } },
  initial: 'live',
  states: {
    live: {
      on: {
        LOGIN: {
          actions: assign({
            session: ({ event }): Session => ({
              kind: 'active',
              token: event.token,
              expiresAt: Date.now() + event.ttlMs,
            }),
          }),
        },
        EXPIRE: {
          actions: assign({
            session: ({ context }): Session =>
              context.session.kind === 'active'
                ? { kind: 'expired', lastToken: context.session.token }
                : context.session,
          }),
        },
        REVOKE: 'revoked',
      },
    },
    revoked: {
      type: 'final',
      output: ({ context }) => ({ finalSession: context.session }),
    },
  },
});
```
